create table if not exists users (id uuid primary key default gen_random_uuid(), email text unique, role text check (role in ('Admin','Staff','Volunteer')) default 'Staff', created_at timestamptz default now());
create table if not exists volunteers (id uuid primary key default gen_random_uuid(), code text unique, name text not null, en_name text, phone text, start_date date, status text default '啟用', transport_eligible boolean default true, remark text, created_at timestamptz default now());
create table if not exists activity_records (id uuid primary key default gen_random_uuid(), activity_name text not null, activity_date date not null, start_time time, end_time time, service_type text, hours numeric default 0, created_by uuid references users(id), created_at timestamptz default now());
create table if not exists case_service_records (id uuid primary key default gen_random_uuid(), service_date date not null, case_no text, service_target text, service_form text, volunteer_id uuid references volunteers(id), start_time time, end_time time, hours numeric default 0, remark text, created_at timestamptz default now());
create table if not exists supervision_records (id uuid primary key default gen_random_uuid(), supervision_date date not null, volunteer_id uuid references volunteers(id), start_time time, end_time time, hours numeric default 0, remark text);
create table if not exists service_records (id uuid primary key default gen_random_uuid(), service_date date not null, record_type text, activity_name text, case_no text, service_target text, service_form text, volunteer_id uuid references volunteers(id), volunteer_name text, start_time time, end_time time, hours numeric default 0, supervision_hours numeric default 0, from_location text, to_location text, transport_method text, transport_fee numeric default 0, remark text, created_at timestamptz default now());
create table if not exists transport_expenses (id uuid primary key default gen_random_uuid(), service_record_id uuid references service_records(id) on delete cascade, from_location text, to_location text, transport_method text, amount numeric default 0);
create table if not exists allowance_records (id uuid primary key default gen_random_uuid(), volunteer_id uuid references volunteers(id), month text not null, service_hours numeric default 0, supervision_hours numeric default 0, transport_fee numeric default 0, hourly_rate numeric default 75, allowance_amount numeric generated always as ((service_hours + supervision_hours) * hourly_rate) stored, grand_total numeric generated always as (((service_hours + supervision_hours) * hourly_rate) + transport_fee) stored, status text default 'draft');
create table if not exists export_templates (id uuid primary key default gen_random_uuid(), template_type text not null, file_path text not null, mappings jsonb default '{}'::jsonb, active boolean default true, created_at timestamptz default now());
create table if not exists settings (id uuid primary key default gen_random_uuid(), key text unique not null, value jsonb not null);
alter table volunteers enable row level security; alter table service_records enable row level security; alter table allowance_records enable row level security;
create policy "staff read volunteers" on volunteers for select using (true); create policy "staff all service records" on service_records for all using (true); create policy "staff all allowance" on allowance_records for all using (true);
